type PostOpenApiV1LighteningDealBidsJSONBody struct {
	// BidsData List of bids to be created.
	BidsData []struct {
		// ProductId The unique identifier of the product (DKP).
		ProductId *int `json:"productId,omitempty"`

		// ProductVariantId The unique identifier of the product variant (DKPC). This ID is closely tied to the product ID.
		ProductVariantId *int `json:"productVariantId,omitempty"`

		// Promotions A list of promotions selected by the seller.
		Promotions *[]struct {
			// AutoRaise The percentage by which the seller is willing to raise their bid if they are losing in the auction.
			AutoRaise *int `json:"autoRaise,omitempty"`

			// MinBid The minimum bid required to participate in the promotion. Typically 7,000,000 for normal products and 3,000,000 for fresh products.
			MinBid *int `json:"minBid,omitempty"`

			// NumberOfVariantsInPromotion The quantity of each product variant the seller wants to offer in the promotion. Should be less than 1000.
			NumberOfVariantsInPromotion *int `json:"numberOfVariantsInPromotion,omitempty"`

			// PaymentMethod The payment method the seller will use, either their wallet balance or credit.
			PaymentMethod *string `json:"paymentMethod,omitempty"`

			// PromotionId The unique identifier of the promotion.
			PromotionId *int `json:"promotionId,omitempty"`

			// PromotionPrice The price the seller wants to offer during the promotion, ending with 00 (IRR).
			PromotionPrice *int `json:"promotionPrice,omitempty"`

			// UpperBound The maximum bid allowed for the promotion. Typically 7,000,000 for normal products and 3,000,000 for fresh products.
			UpperBound *int `json:"upperBound,omitempty"`
		} `json:"promotions,omitempty"`

		// Source The source platform being used to create bids.
		Source *string `json:"source,omitempty"`
	} `json:"bidsData"`
}

