// PostOpenApiV1ShipmentsSellerNewSettingsJSONBody defines parameters for PostOpenApiV1ShipmentsSellerNewSettings.
type PostOpenApiV1ShipmentsSellerNewSettingsJSONBody struct {
	// AutoApprovePendingOrders When true for nearby_shipping, pending shipments are auto-approved at the 20-minute SLA threshold instead of mass cancellation. Only allowed when type is 'nearby_shipping'.
	AutoApprovePendingOrders *bool  `json:"auto_approve_pending_orders,omitempty"`
	Cities                   *[]int `json:"cities,omitempty"`

	// Cost Defines the shipping cost. The cost value can be 0. Otherwise should have these rules:
	//
	//                 - Must be multiple of 100.
	//
	//                 - The maximum value of cost based on its nature in self-shipping settings is:
	//
	//                     - 5000000 for small natures
	//
	//                     - 10000000 for medium natures
	//
	//                     - 100000000 for large natures
	//
	//                 - The maximum value of cost based on its nature in partner-shipping settings is:
	//
	//                     - 2500000 for small natures
	//
	//                     - 5500000 for medium natures
	//
	//                     - 100000000 for large natures
	Cost *int `json:"cost,omitempty"`

	// DynamicTimeScopeId Defines the time scope of the setting and is applicable to the 'self-shipping' type.
	//
	//                 The value can be retrieved from time-scopes list API.
	DynamicTimeScopeId *int `json:"dynamic_time_scope_id,omitempty"`

	// FirstMileDeliveryTime Defines the processing time, measured in days, to prepare the product for delivery to the shipping service provider, such as 'post', and is only applicable to the 'partner-shipping' type.
	//
	//                 Acceptable values are 1|2|3
	FirstMileDeliveryTime *int `json:"first_mile_delivery_time,omitempty"`
	FreeShipping          *struct {
		// Active Enables/Disables free-shipping.
		Active *bool `json:"active,omitempty"`

		// Cost Defines the customer's minimum order amount to qualify for free-shipping.
		//
		//                         The amount value must be multiple of 100.
		Cost *int `json:"cost,omitempty"`
	} `json:"free_shipping,omitempty"`

	// Name Setting name
	Name *string `json:"name,omitempty"`

	// NatureId Defines the product nature. Available natures for both self-shipping and partner-shipping:
	//
	//                 - small: 1
	//
	//                 - medium: 3
	//
	//                 - large: 2
	NatureId int `json:"nature_id"`

	// PicName Person in charge full name for nearby_shipping SMS/IVR. Only allowed when type is 'nearby_shipping'.
	PicName *string `json:"pic_name,omitempty"`

	// PicPhone Person in charge mobile (Iranian format, e.g. 09xxxxxxxxx). Only allowed when type is 'nearby_shipping'.
	PicPhone *string `json:"pic_phone,omitempty"`

	// Status Defines the setting status. Acceptable for existing settings that are not in 'draft' status. Supports active|inactive
	Status *string `json:"status,omitempty"`

	// TimeDistance Defines the processing and delivery time measured in days for delivering the product to the customer and is only applicable to the 'self-shipping' type.
	//
	//                 Acceptable value can be any integer number between 0 and 4.
	//
	//                 Note: A value of 0 means same-day delivery, provided the customer submits the order before 16:00; otherwise, the delivery commitment will be the next day.
	TimeDistance *int `json:"time_distance,omitempty"`

	// TimeScopes Sets the time slots details that seller is able to deliver order to the customer and is only applicable to the 'self-shipping' type.
	TimeScopes *[]struct {
		// Active Defines the time slot active status.
		//
		//                             Accepts true | false.
		Active *bool `json:"active,omitempty"`

		// Capacity Defines the number of orders the seller can deliver in the selected time slot. The active status must be set to true for this to be effective.
		Capacity *int `json:"capacity,omitempty"`

		// Id Sets the selected time-scope slot ID.
		//
		//                             The IDs is retrievable from slots key of time-scopes list API.
		Id *int `json:"id,omitempty"`
	} `json:"time_scopes,omitempty"`

	// WarehouseId Seller warehouse ID used as the origin for nearby delivery. Required for 'nearby_shipping' type.
	WarehouseId *int `json:"warehouse_id,omitempty"`
}

